package com.example.bookmarks.service;

import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import java.io.IOException;

/**
 * Service for managing bookmarks and related operations.
 */
public class BookmarkService {

    /**
     * Fetches the title of a web page from the given URL.
     *
     * @param urlString the URL of the web page
     * @return the text inside the <title> tag of the page
     * @throws IOException if the URL is unreachable, the page has no title, or any other I/O error occurs
     */
    public String fetchTitleFromUrl(String urlString) throws IOException {
        // Validate input
        if (urlString == null || urlString.trim().isEmpty()) {
            throw new IOException("URL cannot be null or empty");
        }

        try {
            // Connect to the URL and fetch the HTML document
            Document doc = Jsoup.connect(urlString)
                    .timeout(10000) // 10 seconds timeout
                    .userAgent("Mozilla/5.0 (compatible; BookmarkService/1.0)")
                    .get();

            // Extract the title from the document
            String title = doc.title();

            // Check if title is empty or null
            if (title == null || title.trim().isEmpty()) {
                throw new IOException("The page does not contain a title");
            }

            return title.trim();
        } catch (IllegalArgumentException e) {
            throw new IOException("Invalid URL format: " + urlString, e);
        } catch (IOException e) {
            throw new IOException("Failed to fetch title from URL: " + urlString, e);
        }
    }
}

